     {q:"A major cause of the Rebellions of 1837-38 was ___.", options:["A cause unrelated to the Rebellions of 1837-38","A dispute over territory with the United States","Demands for greater political representation and reform","A demand to expel all British colonial settlers immediately"], answer:2},
     {q:"Which leader is closely associated with the rebellion in Upper Canada?", options:["William Lyon Mackenzie","A leader unrelated to the Rebellions of 1837-38","John A. Macdonald","George Brown"], answer:0},
     {q:"Which leader is closely associated with the rebellion in Lower Canada?", options:["Louis-Joseph Papineau","Robert Baldwin","Wilfrid Laurier","A leader unrelated to the Rebellions of 1837-38"], answer:0},
     {q:"Why are the Rebellions of 1837-38 considered significant in Canadian history?", options:["They immediately resulted in full independence for the colonies","They had no lasting influence on Canadian political development","A reason unrelated to their historical significance","They contributed to later reforms, including the movement toward responsible government"], answer:3}
